+    #[test]
+    fn resume_plan_serialize_all_fields() {
+        let plan = ResumePlan {
+            progress_file: PathBuf::from("/data/progress.json"),
+            operation: "github.get_issues".to_owned(),
+            total: 100,
+            completed: 42,
+            remaining: 58,
+            remaining_indices: (42..100).collect(),
+        };
+        let json = serde_json::to_value(&plan).unwrap();
